//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: **"fldSimple vs complex field equivalence, attrs, and round-trip"**.
//!
//! Each `#[test]` below encodes a declarative TestSpec mined from the
//! OOXML / Word reference (ISO 29500-1/-4, ECMA-376 Annex A, the normative
//! XSD/RNC schemas, and the MS-* implementer notes). A **FAILING** assertion
//! here is NOT a flaky test to be silenced: it encodes a real Word-compliance
//! gap between stemma and Microsoft Word (the consumption oracle), and a failure
//! is exactly the finding this sweep is hunting. Never weaken an assertion to
//! make it green.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED content
//! byte-verbatim. So `xmlContains` / `xmlOmits` checks on `reserialize()` of an
//! UNEDITED document are valid only for markup the serializer ACTIVELY generates
//! or restructures (child ORDERING per Annex A, structural synthesis, opens-clean
//! validity) and for verbatim-preservation of opaque field machinery (fldData,
//! instr). Consumption semantics ("what reads as the field result") are asserted
//! on the READ side via `read_accepted()` / `read_rejected()`.
//!
//! This file has no `regex` dev-dependency available, so every `xmlRegex`
//! expectation is translated to one-or-more ordered `contains` / byte-offset
//! checks; each such test carries a `// REGEX->CONTAINS:` note explaining the
//! translation.

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude: minimal valid .docx plumbing ──────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is the inner content of `<w:body>`
/// (paragraphs, sectPr, …); it is wrapped in a `<w:document><w:body>…` shell.
///
/// `extra_parts` is a list of `(part_path, xml)` (e.g. `("word/styles.xml", …)`).
/// For each extra part an `<Override>` content-type entry is synthesized from a
/// small known map; unknown part kinds get a generic `application/xml` override.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#
    );

    // Build [Content_Types].xml with overrides for document.xml + any extra parts.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part, _) in extra_parts {
        let ct = content_type_for(part);
        overrides.push_str(&format!(
            r#"<Override PartName="/{part}" ContentType="{ct}"/>"#
        ));
    }
    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );

    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part, xml) in extra_parts {
            zip.start_file(*part, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Content-type override string for a known extra part path.
fn content_type_for(part: &str) -> &'static str {
    match part {
        "word/styles.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
        }
        "word/numbering.xml" => {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
        }
        _ => "application/xml",
    }
}

/// Unzip a `.docx` and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    use std::io::Read;
    let mut zip = zip::ZipArchive::new(std::io::Cursor::new(docx)).expect("zip read");
    let mut xml = String::new();
    let mut f = zip
        .by_name("word/document.xml")
        .expect("document.xml present in package");
    f.read_to_string(&mut xml).expect("read document.xml");
    xml
}

/// Parse → serialize(default) → return the re-emitted `word/document.xml`.
///
/// This is the SAVE-side surface: it reflects what stemma's serializer writes,
/// which for untouched content is its verbatim-preservation contract (see the
/// methodology note at the top).
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse for reserialize");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// Assert the package opens clean: `validate` reports `ok` with no issues.
fn assert_opens_clean(bytes: &[u8], msg: &str) {
    let report = validate(bytes);
    assert!(
        report.ok && report.issues.is_empty(),
        "{msg}\n  validate() reported issues: ok={}, issues={:?}",
        report.ok,
        report.issues
    );
}

