#[test]
fn fldsimple_selfclosing_dirty_no_result_opens_clean() {
    // refs: ISO 29500-1 §17.16.19, §22.9.2.7, ECMA-376 §A.1
    let body = r#"<w:p><w:fldSimple w:instr="AUTHOR" w:dirty="true"/></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "§17.16.19 / §A.1: the self-closing fldSimple (required instr + dirty, \
         no cached result) is the spec's own w:dirty example; it must validate \
         without repair (CT_SimpleField makes EG_PContent minOccurs=0).",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:instr="AUTHOR""#),
        "§17.16.19: instr is required (use=\"required\") and carries the field \
         code; it must reappear in the re-serialized fldSimple. Got XML:\n{xml}",
    );
    assert!(
        xml.contains(r#"w:dirty="true""#),
        "§17.16.19 / §22.9.2.7: dirty is a preserved ST_OnOff attribute; stemma \
         round-trips it verbatim. Got XML:\n{xml}",
    );
}

#[test]
fn fldsimple_dirty_numeric_onoff_form_preserved() {
    // refs: ISO 29500-1 §17.16.19, §22.9.2.7
    // ORACLE(opensClean): Word opens w:dirty="1" without offering repair.
    let body = r#"<w:p><w:fldSimple w:instr=" AUTHOR " w:dirty="1"><w:r><w:t>Rex Jaeschke</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "§22.9.2.7: \"1\" is a valid ST_OnOff on value (\"A value of 1 or true \
         specifies that the property shall be turned on\"), so w:dirty=\"1\" \
         must validate without repair.",
    );
}

#[test]
fn fldsimple_instr_embedded_quoted_arg_preserved() {
    // refs: ISO 29500-1 §17.16.19, §22.9.2.13, §17.16.5.13
    let body = r#"<w:p><w:fldSimple w:instr=" DATE \@ &quot;yyyy&quot; "><w:r><w:t>2025</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "§17.16.19 / §22.9.2.13: a fldSimple whose instr holds an escaped quoted \
         argument (DATE \\@ \"yyyy\") is well-formed (instr is ST_String, required) \
         and must validate without repair.",
    );

    // REGEX->CONTAINS: original xmlRegex = `DATE \\@ (&quot;|\")yyyy(&quot;|\")`.
    // Translated: the re-serialized document.xml must contain the format picture
    // with its embedded quote chars surviving, in EITHER escaped (&quot;) or
    // literal (") form (both are well-formed once the attribute is correctly
    // quoted).
    let xml = reserialize(&b);
    let escaped = xml.contains(r#"DATE \@ &quot;yyyy&quot;"#);
    let literal = xml.contains(r#"DATE \@ "yyyy""#);
    assert!(
        escaped || literal,
        "§22.9.2.13: the quoted format picture (incl. embedded double quotes) must \
         survive in the re-serialized instr attribute, escaped as &quot; or as a \
         literal quote. Found neither `DATE \\@ &quot;yyyy&quot;` nor \
         `DATE \\@ \"yyyy\"` in:\n{xml}",
    );
}

#[test]
fn fldsimple_multiple_result_runs_preserved_and_concatenated() {
    // refs: ISO 29500-1 §17.16.19, §17.16.18, ECMA-376 §A.1
    let body = r#"<w:p><w:fldSimple w:instr=" REF bm "><w:r><w:t>Acme</w:t></w:r><w:r><w:rPr><w:b/></w:rPr><w:t xml:space="preserve"> Corp</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "§17.16.19 / §A.1: a fldSimple with multiple result runs is schema-valid \
         (EG_PContent maxOccurs=unbounded) and must validate without repair.",
    );

    let doc = Document::parse(&b).expect("parse");
    let accepted = doc.read_accepted().expect("read_accepted").to_text();
    assert_eq!(
        accepted.trim(),
        "Acme Corp".trim(),
        "§17.16.19: the displayed field result is the in-order concatenation of \
         all cached result runs (Acme + ' Corp').",
    );
    let rejected = doc.read_rejected().expect("read_rejected").to_text();
    assert_eq!(
        rejected.trim(),
        "Acme Corp".trim(),
        "Untracked field: reject equals accept; the full multi-run cached result \
         reads in both projections.",
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:b/>"),
        "§17.16.19: the second result run's bold rPr must survive; the serializer \
         preserves every result run's structure, not just the first. Got XML:\n{xml}",
    );
}

#[test]
fn fldsimple_flddata_child_precedes_result_runs() {
    // refs: ISO 29500-1 §17.16.19, §17.16.18, ECMA-376 §A.1
    let body = r#"<w:p><w:fldSimple w:instr=" AUTHOR "><w:fldData xml:space="preserve">AQID</w:fldData><w:r><w:t>Rex Jaeschke</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    assert_opens_clean(
        &b,
        "§17.16.19 / §A.1: (fldData?, EG_PContent*) inside a fldSimple is \
         schema-valid and must open without repair.",
    );

    // REGEX->CONTAINS: original xmlRegex =
    //   `<w:fldSimple[^>]*>\s*<w:fldData[^>]*>AQID</w:fldData>\s*<w:r>`
    // i.e. inside the fldSimple, fldData (carrying AQID) precedes the first
    // result run. Without a regex crate we assert the schema-mandated ORDER by
    // checking, relative to the fldSimple open, that fldData appears before the
    // first <w:r>.
    let xml = reserialize(&b);
    let fld_open = xml.find("<w:fldSimple").expect("fldSimple present");
    let after_open = &xml[fld_open..];
    let flddata_pos = after_open
        .find("<w:fldData")
        .expect("fldData present inside/after fldSimple");
    let run_pos = after_open.find("<w:r>").expect("result run present");
    assert!(
        after_open.contains("AQID"),
        "§A.1 CT_SimpleField: the fldData payload AQID must survive. Got XML:\n{xml}",
    );
    assert!(
        flddata_pos < run_pos,
        "§A.1 CT_SimpleField sequence (fldData?, EG_PContent*): fldData must \
         precede the result run inside the fldSimple; the serializer must not \
         reorder or hoist it. fldData@{flddata_pos} run@{run_pos} in:\n{xml}",
    );
}

#[test]
fn fldsimple_flddata_serializes_before_result_run() {
    // refs: ISO 29500-1 §17.16.19, ECMA-376 §A.1 (CT_SimpleField), §22.9.2.13
    // ORACLE(opensClean): Word opens without repair; fldData ordering accepted.
    let body = r#"<w:p><w:r><w:t>X </w:t></w:r><w:fldSimple w:instr="ADDIN ZOTERO_ITEM"><w:fldData>cABhAHkAbABvAGEAZAA=</w:fldData><w:r><w:t>(cached)</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    // REGEX->CONTAINS: original xmlRegex = `<w:fldData[^>]*>[^<]*</w:fldData>\s*<w:r>`
    // i.e. the fldData element (and its text) closes immediately before a result
    // run. We assert the fldData payload survives and that, within the fldSimple,
    // the fldData precedes the first run (the schema-mandated child order).
    let xml = reserialize(&b);
    assert!(
        xml.contains("cABhAHkAbABvAGEAZAA="),
        "The base64 fldData payload must be preserved verbatim through \
         parse->serialize (stemma re-emits the opaque field fragment unchanged). \
         Got XML:\n{xml}",
    );
    let fld_open = xml.find("<w:fldSimple").expect("fldSimple present");
    let after_open = &xml[fld_open..];
    let flddata_pos = after_open.find("<w:fldData").expect("fldData present");
    let run_pos = after_open.find("<w:r>").expect("result run present");
    assert!(
        flddata_pos < run_pos,
        "CT_SimpleField content model is fldData? then EG_PContent*, so fldData \
         must appear before the result run in the re-serialized fldSimple. \
         fldData@{flddata_pos} run@{run_pos} in:\n{xml}",
    );

    assert_opens_clean(
        &b,
        "A CT_SimpleField with required instr and a correctly-ordered fldData \
         child is schema-valid, so Word opens it without repair.",
    );
}

#[test]
fn fldsimple_flddata_nested_not_hoisted_to_sibling() {
    // refs: ISO 29500-1 §17.16.19, ECMA-376 §A.1 (CT_SimpleField)
    let body = r#"<w:p><w:fldSimple w:instr="ADDIN MENDELEY_CITATION"><w:fldData>QUJDREVG</w:fldData><w:r><w:t>[1]</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    // REGEX->CONTAINS: original xmlRegex =
    //   `<w:fldSimple[^>]*>\s*<w:fldData[^>]*>QUJDREVG</w:fldData>`
    // i.e. fldData (carrying QUJDREVG) is the first child INSIDE the fldSimple.
    let xml = reserialize(&b);
    let fld_open = xml.find("<w:fldSimple").expect("fldSimple present");
    // After the fldSimple open tag closes ('>'), the next element must be fldData.
    let tag_end = xml[fld_open..]
        .find('>')
        .expect("fldSimple open tag closes")
        + fld_open
        + 1;
    let after_open_tag = xml[tag_end..].trim_start();
    assert!(
        after_open_tag.starts_with("<w:fldData") && after_open_tag.contains("QUJDREVG"),
        "fldData is a CT_SimpleField child, so on re-serialize it stays the first \
         child INSIDE the fldSimple open tag (carrying QUJDREVG), not a detached \
         sibling. Got XML:\n{xml}",
    );

    assert!(
        !xml.contains("</w:fldSimple><w:fldData>"),
        "fldData must not be hoisted out to sit as a paragraph-level sibling after \
         the fldSimple closes (paragraph content model forbids a bare fldData and \
         the field would lose its blob). Got XML:\n{xml}",
    );

    assert_opens_clean(
        &b,
        "fldData nested correctly inside fldSimple keeps the package schema-valid; \
         Word opens without repair.",
    );
}

#[ignore = "open question: stemma projects fldSimple as cached-result text only; it does not emit begin/instr/separate/end U+FFFC field-anchor placeholders (§17.16.19, §17.16.2)"]
#[test]
fn fldsimple_two_result_runs_both_reproduce_in_text() {
    // refs: ISO 29500-1 §17.16.19, §17.16.2
    let body = r#"<w:p><w:fldSimple w:instr="FILENAME"><w:r><w:t>Example </w:t></w:r><w:r><w:rPr><w:b/></w:rPr><w:t>Document.docx</w:t></w:r></w:fldSimple></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let doc = Document::parse(&b).expect("parse");
    let accepted = doc.read_accepted().expect("read_accepted").to_text();
    assert_eq!(
        accepted.trim(),
        "\u{FFFC}\u{FFFC}\u{FFFC}\u{FFFC}Example Document.docx\u{FFFC}".trim(),
        "§17.16.19: a non-volatile fldSimple projects begin/instr/separate \
         placeholders, then EVERY result run's text in order (Example + \
         Document.docx), then the end placeholder; both result runs must contribute.",
    );
    let rejected = doc.read_rejected().expect("read_rejected").to_text();
    assert_eq!(
        rejected.trim(),
        "\u{FFFC}\u{FFFC}\u{FFFC}\u{FFFC}Example Document.docx\u{FFFC}".trim(),
        "The field is untracked, so reject-all reads the same concatenated cached \
         result as accept-all.",
    );

    assert_opens_clean(
        &b,
        "A fldSimple with multiple EG_PContent result runs is schema-valid and \
         opens without repair.",
    );
}

