    assert!(
        xml.contains("VGhpc0lzQmFzZTY0RmllbGREYXRh"),
        "The Base64 fldData payload Word requires must survive verbatim through \
         parse->serialize (no re-encoding or truncation). Got XML:\n{xml}",
    );

